<template>
  <div class="discovery-cont">
    <el-carousel :interval="4000" type="card" height="230px">
      <el-carousel-item v-for="(item,i) in banners" :key="i">
        <img :src="item.imageUrl" alt="" />
      </el-carousel-item>
    </el-carousel>
    <div class="recommend">
      <h3 class="title">推荐歌单</h3>
      <div class="items">
        <div class="item" v-for="(item, i) in recommed" :key="i" @click="$router.push('/playlist?id='+item.id)">
          <div class="img-wrap">
            <img :src="item.picUrl" alt="" />
            <div class="desc-wrap">
              <span>{{item.name}}</span>
            </div>
            <span class="iconfont icon-icon_play_default"></span>
          </div>
          <p class="name">{{item.copywriter}}</p>
        </div>
      </div>
    </div>
    <!-- 最新音乐 -->
    <div class="news">
      <h3 class="title">最新音乐</h3>
      <div class="items">
        <div class="item" v-for="(item, i) in news" :key="i">
          <div class="img-wrap" @click="goPlay(item.id)">
            <img :src="item.picUrl" alt="" />
            <span class="iconfont icon-icon_play_default"></span>
          </div>
          <div class="songs-wrap">
            <div>{{item.name}}</div>
            <div class="singer">{{item.song.album.artists[0].name}}</div>
          </div>
        </div>
      </div>
    </div>
    <!-- 推荐MV -->
    <div class="mvs">
      <h3 class="title">推荐MV</h3>
      <div class="items">
        <div class="item" v-for="(item,i) in mvsss" :key="i" @click="$router.push('/mv?id='+item.id)">
          <div class="img-wrap">
            <img :src="item.picUrl" alt="" />
            <span class="iconfont icon-icon_play_default"></span>
            <div class="num-wrap">
              <span class="iconfont icon-icon_play_default"></span>
              <span>{{item.playCount|getCount}}</span>
            </div>
          </div>
          <div class="info-wrap">
            <div class="name">{{item.name}}</div>
            <div class="singer">{{item.artistName}}</div>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import music from "@/api/music";
export default {
  data() {
    return {
      banners: [],
      recommed:[],
      news:[],
      mvsss:[]
    };
  },
  methods: {
    // 播放音乐
    async goPlay(id){
      const res = await music.playMusic({
        params:{
          id
        }
      });
      this.$parent.$data.url = res.data[0].url
    },
    // 轮播
    async topBanner() {
      const res = await music.getBanner();
      this.banners = res.banners;
    },
    // 推荐歌单
    async goRecommed(){
      const res = await music.getRecommend({
        params:{
          limit:10
        }
      })
      // console.log(res)
      this.recommed = res.result
    },
    // 最新音乐
    async goNewMusic(){
      const res = await music.getNewMusic()
      // console.log(res)
      this.news = res.result
    },
    // 推荐mv
    async goRecommMv(){
      const res = await music.getMvs()
      // console.log(res)
      this.mvsss = res.result
    }
  },
  created() {
    this.topBanner();
    this.goRecommed();
    this.goNewMusic();
    this.goRecommMv()
  },
};
</script>

<style lang="scss">
.discovery-cont {
  .el-carousel {
    .el-carousel__item {
      img {
        width: 100%;
        height: 100%;
        border-radius: 10px;
      }
    }
  }
  .name {
    overflow: hidden;
    text-overflow: ellipsis;
    display: -webkit-box;
    -webkit-box-orient: vertical;
    -webkit-line-clamp: 1;
    font-size: 14px;
  }
  .title {
    font-weight: normal;
    margin-bottom: 20px;
    padding-left: 8px;
  }
  .recommend {
    margin-bottom: 40px;
    .items {
      display: flex;
      flex-wrap: wrap;
      .item {
        width: 200px;
        margin: 10px;
        overflow: hidden;
        &:hover {
          .img-wrap .desc-wrap {
            top: 0px;
          }
        }
        .img-wrap {
          width: 100%;
          position: relative;
          cursor: pointer;
          &:hover {
            .iconfont {
              opacity: 1;
            }
          }
          img {
            width: 200px;
            height: 200px;
            border-radius: 10px;
          }
          .desc-wrap {
            width: 100%;
            position: absolute;
            left: 0;
            top: -50px;
            background: rgba(0, 0, 0, 0.5);
            color: #fff;
            padding: 5px;
            overflow: hidden;
            text-overflow: ellipsis;
            display: -webkit-box;
            -webkit-box-orient: vertical;
            -webkit-line-clamp: 2;
            span {
              font-size: 14px;
            }
          }
          .icon-icon_play_default {
            position: absolute;
            right: 10px;
            bottom: 13px;
            width: 40px;
            height: 40px;
            color: #dd6d60;
            font-size: 20px;
            border-radius: 50%;
            display: -webkit-box;
            display: -ms-flexbox;
            display: flex;
            -webkit-box-align: center;
            -ms-flex-align: center;
            align-items: center;
            -webkit-box-pack: center;
            -ms-flex-pack: center;
            justify-content: center;
            background: rgba(255, 255, 255, 0.8);
            opacity: 0;
          }
          .icon-icon_play_default::before {
            transform: translateX(3px);
          }
        }
      }
    }
  }
  .news {
    margin-bottom: 40px;
    .items {
      display: flex;
      flex-wrap: wrap;
      padding-left: 15px;
      .item {
        height: 100px;
        width: 50%;
        display: flex;
        align-items: center;
        &:hover {
          background: #f5f5f5;
        }
        .img-wrap {
          cursor: pointer;
          position: relative;
          img {
            width: 80px;
            height: 80px;
          }
          &:hover {
            .iconfont {
              opacity: 1;
            }
          }
          .icon-icon_play_default {
            position: absolute;
            top: 50%;
            left: 50%;
            -webkit-transform: translate(-50%, -50%);
            transform: translate(-50%, -50%);
            width: 30px;
            height: 30px;
            color: #dd6d60;
            text-align: center;
            line-height: 30px;
            border-radius: 50%;
            font-size: 14px;
            background: rgba(255, 255, 255, 0.8);
            opacity: 0;
          }
        }
        .songs-wrap {
          height: 100%;
          padding: 10px;
          display: flex;
          flex-direction: column;
          justify-content: space-around;
          font-size: 16px;
          .singer {
            font-size: 14px;
            color: gray;
          }
        }
      }
    }
  }
  .mvs {
    .items {
      display: flex;
      justify-content: space-around;
      .item {
        width: 250px;
        cursor: pointer;
        .img-wrap {
          width: 100%;
          position: relative;
          &:hover {
            .iconfont {
              opacity: 1;
            }
          }
          img {
            width: 100%;
            border-radius: 5px;
          }
          > .icon-icon_play_default {
            position: absolute;
            top: 50%;
            left: 50%;
            -webkit-transform: translate(-50%, -50%);
            transform: translate(-50%, -50%);
            width: 40px;
            height: 40px;
            color: #dd6d60;
            font-size: 20px;
            border-radius: 50%;
            display: -webkit-box;
            display: -ms-flexbox;
            display: flex;
            -webkit-box-align: center;
            -ms-flex-align: center;
            align-items: center;
            -webkit-box-pack: center;
            -ms-flex-pack: center;
            justify-content: center;
            background: rgba(255, 255, 255, 0.8);
            opacity: 0;
          }
          .icon-icon_play_default::before {
            transform: translateX(3px);
          }
          .num-wrap {
            position: absolute;
            right: 0;
            top: 0;
            color: #fff;
            font-size: 15px;
            padding-right: 5px;
            padding-top: 2px;
            display: flex;
            .iconfont {
              font-size: 12px;
              display: -webkit-box;
              display: -ms-flexbox;
              display: flex;
              -webkit-box-align: center;
              -ms-flex-align: center;
              align-items: center;
              margin-right: 8px;
            }
          }
        }
        .info-wrap {
          .singer {
            font-size: 14px;
            color: #c5c5c5;
            padding-top: 5px;
          }
        }
      }
    }
  }
}
</style>